sql:
SELECT model_name, release_date
FROM golf_cart_models
WHERE voltage = 36 AND discontinued = 0;

external_knowledge:
- "rolling on the green" refers to golf cart models that are still in production (discontinued = 0);
- "production_cost" is the cost to manufacture the golf cart model;
- "voltage" is the battery voltage (36V or 48V) of the golf cart model.

sql:
SELECT AVG(production_cost) AS average_production_cost, AVG(voltage) AS average_voltage
  FROM golf_cart_models
  WHERE discontinued = 0;

SELECT model_name, production_cost
FROM golf_cart_models
ORDER BY production_cost DESC;

SELECT AVG(production_cost) AS average_production_cost
FROM golf_cart_models
WHERE discontinued = 0;

SELECT model_id, model_name, production_cost
FROM golf_cart_models
WHERE discontinued = 0 AND production_cost > (SELECT AVG(production_cost) FROM golf_cart_models);

SELECT model_id
FROM golf_cart_models
WHERE production_cost > (SELECT AVG(production_cost) FROM golf_cart_models);

SELECT MAX(battery_life_years) AS longest_lifespan
FROM battery_performance
WHERE replacement_cost > 400;

